"use client";
import { X, Cpu, Globe, Shield } from 'lucide-react';

export default function DeviceModal({ device, onClose, ports }: any) {
    if (!device) return null;

    return (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
            <div className="bg-white rounded-3xl w-full max-w-lg overflow-hidden shadow-2xl">
                <div className="p-6 border-b flex justify-between items-center bg-slate-900 text-white">
                    <h2 className="text-xl font-bold">Device Details</h2>
                    <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full"><X /></button>
                </div>

                <div className="p-8">
                    <div className="flex items-center gap-6 mb-8">
                        <div className="text-6xl p-4 bg-slate-100 rounded-2xl">
                            {device.category === 'laptop' ? '💻' : device.category === 'phone' ? '📱' : '🌐'}
                        </div>
                        <div>
                            <h3 className="text-2xl font-bold">{device.hostname || "Unknown Host"}</h3>
                            <p className="text-blue-600 font-mono">{device.ip_address}</p>
                        </div>
                    </div>

                    <div className="space-y-4 mb-8">
                        <div className="flex justify-between border-b pb-2">
                            <span className="text-slate-500">MAC Address</span>
                            <span className="font-mono">{device.mac_address}</span>
                        </div>
                        <div className="flex justify-between border-b pb-2">
                            <span className="text-slate-500">Category</span>
                            <span className="capitalize">{device.category}</span>
                        </div>
                    </div>

                    <h4 className="font-bold mb-4 flex items-center gap-2"><Shield className="w-4 h-4" /> Open Ports</h4>
                    <div className="flex flex-wrap gap-2">
                        {ports.length > 0 ? ports.map((p: any) => (
                            <span key={p.id} className="bg-green-100 text-green-700 px-3 py-1 rounded-md text-sm font-bold">
                                PORT {p.port_number} ({p.service})
                            </span>
                        )) : <p className="text-slate-400 italic text-sm">No open ports discovered.</p>}
                    </div>
                </div>
            </div>
        </div>
    );
}